import{c as s,cG as i,cb as a,c8 as n,cf as t,cT as l,ce as h}from"./chunks/framework.BlkIsu1j.js";const e=JSON.parse('{"title":"16. F 与 D 扩展：浮点指令","description":"","frontmatter":{"title":"16. F 与 D 扩展：浮点指令","outline":"deep","layout":"doc","prev":{"text":"15. A 扩展：原子操作指令","link":"/lang/assembly/15_a_extension"},"next":{"text":"17. C 扩展：压缩指令","link":"/lang/assembly/17_c_extension"},"sidebar":true,"date":"2026-05-31T10:00:00.000Z"},"headers":[],"relativePath":"lang/assembly/16_f_d_extension.md","filePath":"lang/assembly/16_f_d_extension.md","lastUpdated":1780202472000}'),p={id:"frontmatter-title",tabindex:"-1"};const d=s({name:"lang/assembly/16_f_d_extension.md"},[["render",function(s,e,d,k,r,c){return i(),a("div",null,[n("h1",p,[t(l(s.$frontmatter.title)+" ",1),e[0]||(e[0]=n("a",{class:"header-anchor",href:"#frontmatter-title","aria-label":"Permalink to “{{ $frontmatter.title }}”"},"​",-1))]),e[1]||(e[1]=h('<p>前 15 章的所有计算都在整数域——寄存器存的是 64 位整数，<code>add</code>/<code>mul</code> 操作的是整数 ALU。但科学计算、图形渲染、信号处理等领域离不开 IEEE 754 浮点数。RISC-V 将浮点支持分层为 F 扩展（单精度，32 位）和 D 扩展（双精度，64 位，依赖 F），引入独立的浮点寄存器文件和完整的 IEEE 754 操作集。本章详述浮点寄存器架构、全部指令族、以及 IEEE 754 在汇编层面的体现。</p><h2 id="浮点扩展概述" tabindex="-1">浮点扩展概述 <a class="header-anchor" href="#浮点扩展概述" aria-label="Permalink to “浮点扩展概述”">​</a></h2><h3 id="f-与-d-的关系" tabindex="-1">F 与 D 的关系 <a class="header-anchor" href="#f-与-d-的关系" aria-label="Permalink to “F 与 D 的关系”">​</a></h3><ul><li><strong>F 扩展</strong>：32 个 32 位浮点寄存器 f0-f31，提供单精度 load/store、算术、比较、转换指令</li><li><strong>D 扩展</strong>：将浮点寄存器扩展为 64 位宽，新增双精度 load/store、算术、单/双精度互转指令。D 依赖 F——无 F 不能有 D</li><li><strong>Q 扩展</strong>（四精度，128 位）和 <strong>Zfh 扩展</strong>（半精度，16 位）同样是独立扩展</li></ul><p>汇编助记符中以 <code>.s</code> 结尾的是单精度操作，以 <code>.d</code> 结尾的是双精度操作。在 D 扩展存在时，浮点寄存器实际为 64 位宽——存单精度值时只用低 32 位，高 32 位保持为 NaN-boxing（全 1）。</p><h3 id="独立的寄存器文件" tabindex="-1">独立的寄存器文件 <a class="header-anchor" href="#独立的寄存器文件" aria-label="Permalink to “独立的寄存器文件”">​</a></h3><p>浮点寄存器 f0-f31 与整数寄存器 x0-x31 是<strong>完全独立</strong>的寄存器文件——这在 RISC-V 设计中是唯一的多寄存器文件场景。两者之间无法直接搬移数据，必须通过以下途径：</p><ul><li><strong>内存中转</strong>：整数 store → 浮点 load（或反之）</li><li><strong>fcvt 转换指令</strong>：直接在同一操作中搬移位模式并转换格式</li><li><strong>fmov</strong>（RV64D 提供）：直接复制位模式（不转换）</li></ul><p>这也带来一个性能微架构提示：整数和浮点寄存器文件之间的数据传输通常需跨越执行单元的端口，延迟比寄存器文件内部移动大 1-2 个周期。</p><h2 id="浮点寄存器-abi" tabindex="-1">浮点寄存器 ABI <a class="header-anchor" href="#浮点寄存器-abi" aria-label="Permalink to “浮点寄存器 ABI”">​</a></h2><h3 id="命名与用途" tabindex="-1">命名与用途 <a class="header-anchor" href="#命名与用途" aria-label="Permalink to “命名与用途”">​</a></h3><table tabindex="0"><thead><tr><th>寄存器</th><th>ABI 名称</th><th>分类</th><th>用途</th></tr></thead><tbody><tr><td>f0-f7</td><td>ft0-ft7</td><td>caller-saved</td><td>浮点临时寄存器</td></tr><tr><td>f8-f9</td><td>fs0-fs1</td><td>callee-saved</td><td>浮点被保存寄存器</td></tr><tr><td>f10-f11</td><td>fa0-fa1</td><td>caller-saved</td><td>浮点参数/返回值</td></tr><tr><td>f12-f17</td><td>fa2-fa7</td><td>caller-saved</td><td>浮点参数 3-7</td></tr><tr><td>f18-f27</td><td>fs2-fs11</td><td>callee-saved</td><td>浮点被保存寄存器</td></tr><tr><td>f28-f31</td><td>ft8-ft11</td><td>caller-saved</td><td>临时寄存器</td></tr></tbody></table><p>与整数 ABI 的结构镜像——参数寄存器（fa0-fa7）对齐 a0-a7，临时寄存器（ft）对齐 t 系列。注意浮点被保存寄存器 fs0-fs11 共 12 个，比整数 s0-s11 多 1 个（整数的 s0/fp 被 x8 占用，浮点的 fs0 从 f8 开始）。</p><h3 id="fcsr-浮点控制状态寄存器" tabindex="-1">fcsr：浮点控制状态寄存器 <a class="header-anchor" href="#fcsr-浮点控制状态寄存器" aria-label="Permalink to “fcsr：浮点控制状态寄存器”">​</a></h3><p>fcsr 汇集浮点运算的舍入模式和异常标志——它不是通过常规读写在寄存器文件中访问，而是通过专门的 CSR 指令：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">frcsr t0               </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 读 fcsr 到整数寄存器</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fscsr t0, t1           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 写 t1 到 fcsr，旧值存入 t0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fscsr t1               </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # fscsr x0, t1 —— 写 fcsr，丢弃旧值</span></span></code></pre></div><p>fcsr 的位域结构：</p><table tabindex="0"><thead><tr><th>位</th><th>字段</th><th>说明</th></tr></thead><tbody><tr><td>7:5</td><td>frm</td><td>舍入模式：000=RNE, 001=RTZ, 010=RDN, 011=RUP, 100=RMM</td></tr><tr><td>4</td><td>NV</td><td>Invalid Operation 异常标志</td></tr><tr><td>3</td><td>DZ</td><td>Divide by Zero 异常标志</td></tr><tr><td>2</td><td>OF</td><td>Overflow 异常标志</td></tr><tr><td>1</td><td>UF</td><td>Underflow 异常标志</td></tr><tr><td>0</td><td>NX</td><td>Inexact 异常标志</td></tr></tbody></table><p>大多数浮点指令自带 3 位 rm（舍入模式）字段，若其值为 <code>111</code> 则使用 fcsr 中的 frm 域；否则使用指令指定的舍入模式。这条设计让指令可以在需要的时刻精确控制舍入——称为&quot;动态舍入&quot;，是 RISC-V 浮点设计的独到之处。</p><h2 id="浮点-load-store" tabindex="-1">浮点 Load/Store <a class="header-anchor" href="#浮点-load-store" aria-label="Permalink to “浮点 Load/Store”">​</a></h2><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 单精度</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flw  rd, offset(rs1)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = sign_ext(MEM[rs1 + offset][31:0])，加载到 f 寄存器</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsw  rs2, offset(rs1)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # MEM[rs1 + offset] = rs2[31:0]</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 双精度</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fld</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  rd, offset(rs1)   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = MEM[rs1 + offset]（64 位）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsd  rs2, offset(rs1)  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # MEM[rs1 + offset] = rs2</span></span></code></pre></div><p>语法与整数 <code>lw</code>/<code>sw</code>/<code>ld</code>/<code>sd</code> 完全一致——寻址方式（基址 + 12 位有符号偏移）、宽度（32 或 64 位）、对齐要求都同模同构。唯一区别是目标/源在 f 寄存器文件而非 x 寄存器文件。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 示例：从栈加载和存储浮点值</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fld</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  fa0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">0</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # fa0 = *(double*)sp</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsd  fs0, </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">(</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">sp</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">)         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # *(double*)(sp+8) = fs0</span></span></code></pre></div><p>opcode：浮点 load 为 <code>0000111</code>，浮点 store 为 <code>0100111</code>；funct3=010 为单精度，funct3=011 为双精度。</p><h2 id="浮点运算指令" tabindex="-1">浮点运算指令 <a class="header-anchor" href="#浮点运算指令" aria-label="Permalink to “浮点运算指令”">​</a></h2><h3 id="基本算术" tabindex="-1">基本算术 <a class="header-anchor" href="#基本算术" aria-label="Permalink to “基本算术”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 单精度（.s）和双精度（.d）形式</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fadd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.s  rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = rs1 + rs2</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fadd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d  rd, rs1, rs2</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fsub</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.s  rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = rs1 - rs2</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fsub</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d  rd, rs1, rs2</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fmul</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.s  rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = rs1 * rs2</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fmul</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d  rd, rs1, rs2</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fdiv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.s  rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = rs1 / rs2</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fdiv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d  rd, rs1, rs2</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fsqrt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.s rd, rs1         </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = sqrt(rs1)（rs2 不使用）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fsqrt</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d rd, rs1</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 最小值/最大值</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fmin.s  rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = min(rs1, rs2)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fmax.s  rd, rs1, rs2   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = max(rs1, rs2)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fmin.d  rd, rs1, rs2</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fmax.d  rd, rs1, rs2</span></span></code></pre></div><p>R-type，opcode=<code>1010011</code>。精度由指令格式字段（bits 26:25 = funct2）指示：00=单精度(.s)、01=双精度(.d)。操作由 funct5（bits 31:27）指示：00000=fadd、00001=fsub、00010=fmul、00011=fdiv、01011=fsqrt、00101=fmin/fmax（funct3=000 为 min，funct3=001 为 max）。</p><h3 id="符号注入指令" tabindex="-1">符号注入指令 <a class="header-anchor" href="#符号注入指令" aria-label="Permalink to “符号注入指令”">​</a></h3><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsgnj.s  rd, rs1, rs2  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = {rs2[31], rs1[30:0]}（注入符号）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsgnjn.s rd, rs1, rs2  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = {~rs2[31], rs1[30:0]}（注入反符号）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsgnjx.s rd, rs1, rs2  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = {rs1[31] ^ rs2[31], rs1[30:0]}（异或符号）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsgnj.d  rd, rs1, rs2</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsgnjn.d rd, rs1, rs2</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fsgnjx.d rd, rs1, rs2</span></span></code></pre></div><p>这些指令不执行算术操作——只修改符号位。它们是 <code>fabs</code>（取绝对值，<code>fsgnj.s rd, rs1, rs1</code> 并在 rs1 的符号位清零）、<code>fneg</code>（取负，<code>fsgnjn.s rd, rs1, rs1</code>）的底层硬件实现。RISC-V 没有独立的 <code>fabs</code>/<code>fneg</code> 指令，汇编器将这些伪指令展开为 <code>fsgnj</code>/<code>fsgnjn</code>。</p><h3 id="融合乘加-fma" tabindex="-1">融合乘加（FMA） <a class="header-anchor" href="#融合乘加-fma" aria-label="Permalink to “融合乘加（FMA）”">​</a></h3><p>FMA 是浮点计算中的重型操作——在一条指令中计算 <code>a * b + c</code>，且只在最后舍入一次（而非先舍入乘法的结果再舍入加法）。RISC-V 提供四种变体：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 格式: op rd, rs1, rs2, rs3  —— 四个寄存器操作数！</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fmadd.s  rd, rs1, rs2, rs3  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (rs1 * rs2) + rs3</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fmsub.s  rd, rs1, rs2, rs3  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (rs1 * rs2) - rs3</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fnmsub.s rd, rs1, rs2, rs3  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = -(rs1 * rs2) + rs3</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fnmadd.s rd, rs1, rs2, rs3  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = -(rs1 * rs2) - rs3</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fmadd.d  rd, rs1, rs2, rs3</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fmsub.d  rd, rs1, rs2, rs3</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fnmsub.d rd, rs1, rs2, rs3</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fnmadd.d rd, rs1, rs2, rs3</span></span></code></pre></div><p>FMA 使用独立的 R4-type 格式（4 个寄存器 + 2 位格式指示），opcode 分别为 <code>1000011</code>（fmadd）、<code>1000111</code>（fmsub）、<code>1001011</code>（fnmsub）、<code>1001111</code>（fnmadd）。这是 RISC-V 中唯一的四寄存器指令格式——三个源寄存器（rs1, rs2, rs3）加一个目标寄存器（rd）。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># FMA 使用示例：双线性插值 a*(1-t) + b*t</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 设 fa0=a, fa1=b, fa2=t, fa3=1.0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fmsub.d ft0, fa0, fa2, fa0   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # ft0 = a*t - a = a*(t-1)</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fmsub.d ft1, fa1, fa2, ft0   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # ft1 = b*t - a*(t-1) = a*(1-t) + b*t</span></span></code></pre></div><p>FMA 在数值精度上优于分开的乘法+加法——单次舍入减少了累积误差。在高性能数值计算（矩阵乘、卷积、多项式求值）中，编译器会积极将 <code>a*b + c</code> 模式转化为 FMA。</p><h2 id="转换指令" tabindex="-1">转换指令 <a class="header-anchor" href="#转换指令" aria-label="Permalink to “转换指令”">​</a></h2><p>浮点与整数之间的转换、不同精度之间的互转，在 RISC-V 中通过统一的 <code>fcvt</code> 指令族完成：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 浮点 → 整数</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.w.s   rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (int32_t)rs1       有符号，单精度</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.wu.s  rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> #                       无符号版本</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.l.s   rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (int64_t)rs1       有符号，单精度</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.lu.s  rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> #                       无符号版本</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.w.d   rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (int32_t)rs1       有符号，双精度</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.wu.d  rd, rs1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.l.d   rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (int64_t)rs1       有符号，双精度</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.lu.d  rd, rs1</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 整数 → 浮点</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.s.w   rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (float)rs1         有符号，结果单精度</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.s.wu  rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> #                       无符号版本</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.s.l   rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 64 位整数 → 单精度</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.s.lu  rd, rs1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.d.w   rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (double)rs1        有符号，结果双精度</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.d.wu  rd, rs1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.d.l   rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 64 位整数 → 双精度</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.d.lu  rd, rs1</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 浮点精度互转</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.s.d   rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (float)(double)rs1   双→单</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fcvt.d.s   rd, rs1       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (double)(float)rs1   单→双</span></span></code></pre></div><p>转换指令的 R-type 编码中，rs2 字段指示源格式（<code>00000</code>=.s, <code>00001</code>=.d，对于整数转换，rs2 指示有/无符号），而 funct7 的高位指示方向和目标格式。大值转换超出目标范围时触发 NV 异常标志，并返回适当值（最大/最小/无穷大）。</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 示例：华氏温度转摄氏温度</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># fa0 = 华氏温度（双精度）</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fld</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    fa1, const_32, t0      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # fa1 = 32.0</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fld</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    fa2, const_5over9, t0  </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # fa2 = 5.0 / 9.0</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fmul</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d fa0, fa0, fa2          </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # f * (5/9)  → 注意这里是伪代码，演示转换思路</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">fsub</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d fa0, fa0, fa1</span></span></code></pre></div><h2 id="浮点比较" tabindex="-1">浮点比较 <a class="header-anchor" href="#浮点比较" aria-label="Permalink to “浮点比较”">​</a></h2><p>浮点比较指令结果写入<strong>整数寄存器</strong>（不是浮点寄存器）——0 或 1：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">feq.s  rd, rs1, rs2    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (rs1 == rs2) ? 1 : 0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">feq.d  rd, rs1, rs2</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flt.s  rd, rs1, rs2    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (rs1 &lt; rs2)  ? 1 : 0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flt.d  rd, rs1, rs2</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fle.s  rd, rs1, rs2    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # rd = (rs1 &lt;= rs2) ? 1 : 0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fle.d  rd, rs1, rs2</span></span></code></pre></div><p>R-type，opcode=<code>1010011</code>；funct3=010 为 feq，funct3=001 为 flt，funct3=000 为 fle。结果通过整数寄存器传递——这让你能用普通的 <code>beq</code>/<code>bne</code>/<code>beqz</code>/<code>bnez</code> 对浮点比较结果做分支：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># if (fa0 &lt; fa1) goto loop</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flt.d  t0, fa0, fa1</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">bnez   t0, </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">loop</span></span></code></pre></div><p>与整数的 <code>slt</code> 逻辑一致——不设标志位，结果写寄存器，再配合分支指令做条件跳转。RISC-V 从始至终没有条件码寄存器。</p><h3 id="nan-行为" tabindex="-1">NaN 行为 <a class="header-anchor" href="#nan-行为" aria-label="Permalink to “NaN 行为”">​</a></h3><p>IEEE 754 规定任何与 NaN 的比较都应返回 false（无序比较）。RISC-V 严格遵循：</p><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 设 fa0 = NaN, fa1 = 5.0</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">feq.s  t0, fa0, fa1    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = 0（NaN 不等于任何值，包括 NaN 自身）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">flt.s  t0, fa0, fa1    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = 0（NaN &lt; 5.0 → false）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">fle.s  t0, fa0, fa1    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = 0（NaN &lt;= 5.0 → false）</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">feq.s  t0, fa0, fa0    </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # t0 = 0（NaN != NaN）</span></span></code></pre></div><p>要检测 NaN，使用 <code>fclass</code> 指令或等价的比较——<code>feq.s t0, fa0, fa0</code>，t0=0 说明源是 NaN。</p><h2 id="完整示例-平方根逼近-newton-法" tabindex="-1">完整示例：平方根逼近（Newton 法） <a class="header-anchor" href="#完整示例-平方根逼近-newton-法" aria-label="Permalink to “完整示例：平方根逼近（Newton 法）”">​</a></h2><div class="language-asm"><button title="Copy Code" class="copy"></button><span class="lang">asm</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># 用 Newton 法逼近 sqrt(x) —— 双精度</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># fa0 = x, 返回 fa0 = sqrt(x)</span></span>\n<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># y_{n+1} = (y_n + x / y_n) / 2</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sqrt_newton:</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    fld</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     ft0, two, t0       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # ft0 = 2.0</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    fdiv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d  ft1, fa0, ft0      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 初始猜测: y = x / 2</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">sqrt_loop:</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    fmv.d   ft2, ft1           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 保存当前 y</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    fdiv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d  ft3, fa0, ft1      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # ft3 = x / y</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    fadd</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d  ft1, ft1, ft3      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # ft1 = y + x/y</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    fdiv</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d  ft1, ft1, ft0      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # ft1 = (y + x/y) / 2</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    fsub</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d  ft4, ft1, ft2      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 变化 = new_y - old_y</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    fabs</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.d  ft4, ft4           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # abs(变化)</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    fld</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     ft5, epsilon, t0   </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # ft5 = 收敛阈值</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    flt.d   t1, ft5, ft4       </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # abs(变化) &gt; epsilon ?</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    bnez    t1, sqrt_loop      </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 未收敛，继续迭代</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">    fmv.d   fa0, ft1           </span><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"> # 返回值</span></span>\n<span class="line"><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">    ret</span></span>\n<span class="line"></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">.data</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">two:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">     .double </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">2.0</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">epsilon:</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> .double </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">1e-12</span></span></code></pre></div><p>实际生产代码中，硬件 <code>fsqrt.d</code> 比 Newton 迭代快数十倍——这个例子意在展示浮点指令序列在数值算法中的用法。</p><h2 id="本章要点" tabindex="-1">本章要点 <a class="header-anchor" href="#本章要点" aria-label="Permalink to “本章要点”">​</a></h2><ul><li>F 扩展提供 32 个 32 位浮点寄存器，D 扩展扩展为 64 位并新增双精度操作；f0-f31 与 x0-x31 独立，数据移动需经 load/store 或转换指令</li><li>fcsr 控制舍入模式（5 种）和异常标志（5 种）；动态舍入（rm=111 时使用 fcsr 的 frm）为每指令精确控制提供硬件支持</li><li>浮点算术（fadd/fsub/fmul/fdiv/fsqrt/fmin/fmax）和符号注入（fsgnj/fsgnjn/fsgnjx）使用 opcode=<code>1010011</code>，精度由指令格式位指示</li><li>融加乘（FMA）以四寄存器格式（R4-type）在一条指令内完成 a*b+c 且单次舍入——数值算法的精度和性能基石</li><li>浮点比较结果写入整数寄存器（0/1），配合 bne/beq 做分支；NaN 上所有比较返回 false——严格遵循 IEEE 754</li></ul>',57))])}]]);export{e as __pageData,d as default};
